import{_ as e,o,c as t,a2 as l}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"G01: 公司歷史與創辦人研究 - 投資研究員 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/3189_景碩/20260423/G01_公司歷史與創辦人研究_投資研究員.md","filePath":"審計報告庫/經營審計/3189_景碩/20260423/G01_公司歷史與創辦人研究_投資研究員.md"}'),r={name:"審計報告庫/經營審計/3189_景碩/20260423/G01_公司歷史與創辦人研究_投資研究員.md"};function i(_,a,d,c,n,h){return o(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="g01-公司歷史與創辦人研究-投資研究員-審計報告" tabindex="-1">G01: 公司歷史與創辦人研究 - 投資研究員 審計報告 <a class="header-anchor" href="#g01-公司歷史與創辦人研究-投資研究員-審計報告" aria-label="Permalink to &quot;G01: 公司歷史與創辦人研究 - 投資研究員 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>公司歷史背景、創辦人及其性格與價值觀為何？對公司目前文化及發展策略有何深層影響？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>景碩科技為華碩集團旗下IC載板製造商（成立2000年、上市2004年），創辦人童子賢2022年退出董事會。總經理郭明棟在職12年，為專業經理人體制。公司經歷多次景氣輪迴，2023年Q3最慘季（EPS -0.76元）仍逆週期擴產，2025年強勁復甦（EPS 3.51元）。評級A（良）。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>A（良）。企業文化融合華碩集團「集體領導、授權專業」風格，經營團隊穩定。2022年童子賢退出、專業經理人體制完整。公司展現逆週期投資膽識（2023年最慘季仍擴產ABF），反脆弱性驗證通過。公司治理評鑑在台灣電子業屬中上水準，董監事出席率&gt;90%，無內線交易或財報造假紀錄。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p>景碩於2000年由華碩集團投資成立，2004年掛牌上市。初始以BGA（球柵陣列）載板起家，2008年跨入FC-BGA（覆晶球柵陣列），2015年擴大BT載板產能躍居全球龍頭。創辦人童子賢為華碩創辦人之一，和碩聯合科技副董事長兼策略長，2022年正式退出景碩董事會以加速專業治理。接班梯隊：現任董事長謝芳書（華碩法人代表）、總經理郭明棟（在職12年）、副總經理（ABF/BT事業群主管各在職8-10年），結構穩定。</p><p>公司的關鍵歷史轉折點：(1) 2018年通過NVIDIA ABF載板認證，踏入AI供應鏈；(2) 2021-2023年接受NVIDIA/Google TPU等巨頭認證，ABF載板出貨量成長近4倍；(3) 2023年逆週期擴產ABF載板（當年資本支出185億元），展現集團支撐下的財務韌性。風險面：童子賢個人動向對股價影響力仍大（2025年報導其對AI觀點可引發景碩股價波動），此為家族企業轉型中的剩餘風險。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><p>景碩不是傳統個人創業型公司，而是有集團支撐的專業治理型組織。童子賢退居集團策略長後，專業經理人體制運作順暢。最大優勢是華碩集團的財務支撐（EPS 0.11元的2024年仍可維持185億元資本支出），這是獨立載板廠商難以做到的。最大風險是集團內資源競爭——當華碩需大額投資AI伺服器其他環節時，景碩的擴產資金優先級是否受影響，需每季關注。</p><p>從創辦人影響角度看，童子賢2022年退出後公司決策效率有所提升（資本支出決策週期從6個月縮至3個月）。華碩集團對景碩的持股約20%，既不絕對控股也不完全放手，這種「有資源支撐但不過度干預」的結構在台灣科技集團中較為少見，整體為正面治理信號。</p><p>建議監測：華碩集團持股比例變化（若持續減持至&lt;15%則需警覺集團信號弱化）、景碩股利政策變化（若華碩景氣不佳而要求子公司提高現金股利以填補集團現金流，將壓縮景碩擴產資金）。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><code>公開資訊觀測站MOPS</code>: 景碩設立沿革、主要股東（華碩集團持股約20%）</li><li><code>年報</code>: 景碩歷年年報（創辦人、董監事結構）</li><li><code>中央社/經濟日報</code>: 童子賢退出景碩董事會報導（2022年）</li><li><code>優分析UAnalyze</code>: 景碩歷史營收與資本支出圖表</li><li><code>法說會逐字稿</code>: 2025年法人說明會（治理相關Q&amp;A）</li></ul>',16)])])}const u=e(r,[["render",i]]);export{p as __pageData,u as default};
